function isAlogyMonetizablePage(){
  const path = window.location.pathname.split('/').pop() || 'index.html';
  const robots = (document.querySelector('meta[name="robots"]')?.content || '').toLowerCase();
  if(robots.includes('noindex')) return false;
  if(ALOGY_ADS_CONFIG.institutionalPages.has(path)) return false;
  if(ALOGY_ADS_CONFIG.legalPages.has(path)) return false;
  if(ALOGY_ADS_CONFIG.retiredPages.has(path)) return false;
  if(ALOGY_ADS_CONFIG.reviewHoldPages.has(path)) return false;
  if(ALOGY_ADS_CONFIG.editorialReviewPages.has(path)) return false;

  // Artigos e hubs editoriais são elegíveis por padrão. Ferramentas continuam
  // em lista branca individual para evitar monetização acidental de páginas críticas.
  if(path === 'blog.html' || path.startsWith('blog-')) return true;
  if(path === 'ferramentas.html' || path.startsWith('ferramentas-')) return true;
  return ALOGY_ADS_CONFIG.eligiblePages.has(path);
}

function hasAdsenseData(slot){
  return !!(ALOGY_ADS_CONFIG.enabled && ALOGY_ADS_CONFIG.siteApproved && ALOGY_ADS_CONFIG.manualUnitsEnabled && ALOGY_ADS_CONFIG.adClient && slot);
}

function shouldLoadAlogyAdsense(){
  if(!ALOGY_ADS_CONFIG.enabled || !ALOGY_ADS_CONFIG.siteApproved || !ALOGY_ADS_CONFIG.adClient) return false;
  if(!isAlogyMonetizablePage()) return false;
  return ALOGY_ADS_CONFIG.manualUnitsEnabled;
}

function loadAlogyAdsenseScript(){
  if(!shouldLoadAlogyAdsense()) return;
  if(document.querySelector('script[data-alogy-adsense="true"], script[src*="pagead2.googlesyndication.com/pagead/js/adsbygoogle.js"]')) return;

  const script = document.createElement('script');
  script.async = true;
  script.crossOrigin = 'anonymous';
  script.setAttribute('data-alogy-adsense', 'true');
  script.src = `https://pagead2.googlesyndication.com/pagead/js/adsbygoogle.js?client=${encodeURIComponent(ALOGY_ADS_CONFIG.adClient)}`;
  document.head.appendChild(script);
}

function createAlogyAdUnit(slot, type){
  const wrap = document.createElement(type === 'mobile' ? 'div' : 'aside');
  wrap.className = type === 'mobile' ? 'alogy-mobile-ad no-print' : `alogy-ad-rail alogy-ad-${type} no-print`;
  wrap.setAttribute('aria-label', 'Publicidade');

  const label = document.createElement('div');
  label.className = 'alogy-ad-label';
  label.textContent = 'Publicidade';

  const slotBox = document.createElement('div');
  slotBox.className = type === 'mobile' ? 'alogy-ad-slot alogy-ad-slot-mobile' : 'alogy-ad-slot alogy-ad-slot-vertical';

  const ins = document.createElement('ins');
  ins.className = 'adsbygoogle';
  ins.style.display = 'block';
  ins.setAttribute('data-ad-client', ALOGY_ADS_CONFIG.adClient);
  ins.setAttribute('data-ad-slot', slot);
  ins.setAttribute('data-full-width-responsive', 'true');

  if(type === 'mobile'){
    ins.setAttribute('data-ad-format', 'auto');
  }else{
    ins.style.width = '160px';
    ins.style.height = '600px';
  }

  slotBox.appendChild(ins);
  wrap.appendChild(label);
  wrap.appendChild(slotBox);
  return wrap;
}

function pushAlogyAds(){
  if(!ALOGY_ADS_CONFIG.enabled || !ALOGY_ADS_CONFIG.siteApproved) return;
  window.adsbygoogle = window.adsbygoogle || [];
  document.querySelectorAll('.alogy-ad-slot ins.adsbygoogle:not([data-alogy-pushed="true"])').forEach((ins) => {
    try{
      (window.adsbygoogle = window.adsbygoogle || []).push({});
      ins.setAttribute('data-alogy-pushed', 'true');
    }catch(err){
      console.warn('AdSense ainda não disponível:', err);
    }
  });
}

function insertAlogyMobileAd(main){
  if(!hasAdsenseData(ALOGY_ADS_CONFIG.mobileSlot)) return;
  if(main.querySelector('.alogy-mobile-ad')) return;

  // Posição conservadora: ao final do conteúdo principal, longe de campos,
  // botões, resultados e navegação. A ativação continua condicionada às travas.
  const mobileAd = createAlogyAdUnit(ALOGY_ADS_CONFIG.mobileSlot, 'mobile');
  mobileAd.setAttribute('data-alogy-placement', 'end-of-main');
  main.appendChild(mobileAd);
}

function initAlogyAdsLayout(){
  if(!isAlogyMonetizablePage()) return;

  const main = document.querySelector('main.container');
  if(!main || main.dataset.alogyAdsReady === 'true') return;

  const desktopLeft = hasAdsenseData(ALOGY_ADS_CONFIG.desktopLeftSlot);
  const desktopRight = hasAdsenseData(ALOGY_ADS_CONFIG.desktopRightSlot);
  const mobile = hasAdsenseData(ALOGY_ADS_CONFIG.mobileSlot);

  // Unidades manuais são opcionais. Auto Ads e Side Rail usam o script geral
  // já presente apenas nas páginas elegíveis e são controlados no painel.
  if(!shouldLoadAlogyAdsense()) return;

  loadAlogyAdsenseScript();
  main.dataset.alogyAdsReady = 'true';

  if(!desktopLeft && !desktopRight && !mobile) return;

  if(desktopLeft || desktopRight){
    const wrapper = document.createElement('div');
    wrapper.className = 'alogy-ad-layout no-print';

    const content = document.createElement('div');
    content.className = 'alogy-ad-main';

    main.parentNode.insertBefore(wrapper, main);

    if(desktopLeft){
      wrapper.appendChild(createAlogyAdUnit(ALOGY_ADS_CONFIG.desktopLeftSlot, 'left'));
    }else{
      const spacer = document.createElement('div');
      spacer.className = 'alogy-ad-rail alogy-ad-spacer';
      wrapper.appendChild(spacer);
    }

    content.appendChild(main);
    wrapper.appendChild(content);

    if(desktopRight){
      wrapper.appendChild(createAlogyAdUnit(ALOGY_ADS_CONFIG.desktopRightSlot, 'right'));
    }else{
      const spacer = document.createElement('div');
      spacer.className = 'alogy-ad-rail alogy-ad-spacer';
      wrapper.appendChild(spacer);
    }
  }

  insertAlogyMobileAd(main);
  setTimeout(pushAlogyAds, 700);
}

function ensurePrivacyFooterLink(){
  document.querySelectorAll('footer').forEach((footer) => {
    let line = footer.querySelector('.footer-legal-links');
    if(!line){
      line = document.createElement('p');
      line.className = 'footer-legal-links no-print';
      footer.appendChild(line);
    }

    const links = [];
    if(!footer.querySelector('a[href="politica-de-privacidade.html"]')){
      links.push('<a href="politica-de-privacidade.html">Política de Privacidade e Cookies</a>');
    }
    if(!footer.querySelector('a[href="termos-de-uso-ferramentas.html"]')){
      links.push('<a href="termos-de-uso-ferramentas.html">Termos de Uso das Ferramentas</a>');
    }

    if(links.length){
      const current = line.innerHTML.trim();
      line.innerHTML = current ? `${current} · ${links.join(' · ')}` : links.join(' · ');
    }
  });
}





/* =========================
   ETAPA 3 - MELHORIA CONSERVADORA DE USABILIDADE DOS FORMULÁRIOS
   Não altera fórmulas, funções de cálculo nem eventos existentes.
========================= */
function enhanceToolFormsUsability(){
  const path = window.location.pathname.split('/').pop() || 'index.html';
  if(path === 'calculadora-dimensionamento-cabos.html') return;
  if(!document.body?.classList.contains('alogy-stage3-forms')) return;

  const isVisibleControl = (el) => {
    if(!el) return false;
    const type = (el.getAttribute('type') || '').toLowerCase();
    return !['hidden','button','submit','reset'].includes(type);
  };

  const controlSelector = 'input, select, textarea';
  document.querySelectorAll(`main ${controlSelector}`).forEach((el) => {
    if(!isVisibleControl(el)) return;

    el.classList.add('alogy-control');

    const type = (el.getAttribute('type') || '').toLowerCase();
    if(type === 'number' && !el.hasAttribute('inputmode')){
      el.setAttribute('inputmode', 'decimal');
    }

    if(!el.hasAttribute('aria-label')){
      let labelText = '';
      if(el.id){
        const safeId = (window.CSS && CSS.escape) ? CSS.escape(el.id) : el.id.replace(/"/g, '\\"');
        const label = document.querySelector(`label[for="${safeId}"]`);
        if(label) labelText = label.textContent.trim();
      }
      if(!labelText){
        const parentLabel = el.closest('label');
        if(parentLabel) labelText = parentLabel.textContent.trim();
      }
      if(labelText) el.setAttribute('aria-label', labelText.replace(/\s+/g, ' '));
    }
  });

  const addNote = (container) => {
    if(!container || container.dataset.alogyStage3Note === 'true') return;
    if(container.querySelector(':scope > .tool-form-note')) return;

    const controls = Array.from(container.querySelectorAll(controlSelector)).filter(isVisibleControl);
    if(controls.length < 8) return;

    const note = document.createElement('p');
    note.className = 'tool-form-note no-print';
    note.innerHTML = '<strong>Dica de preenchimento:</strong> confira as unidades dos campos e preencha primeiro os dados principais antes de calcular.';

    const firstGrid = container.querySelector('.calc-grid, .form-grid, .field-grid');
    if(firstGrid && firstGrid.parentElement === container){
      container.insertBefore(note, firstGrid);
    }else{
      container.insertBefore(note, container.firstChild);
    }
    container.dataset.alogyStage3Note = 'true';
  };

  document.querySelectorAll('main form').forEach(addNote);

  document.querySelectorAll('main .calc-card').forEach((card) => {
    if(card.querySelector('form')) return;
    if(!card.querySelector('.calc-grid, .form-grid, .field-grid')) return;
    addNote(card);
  });
}


